  ('retired-10ced7e2-moex-00207', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-3a7b2121', 'sub-retired-10ced7e2-05', NULL, 'single_choice', '根據我國相關法律之規定，公務人員從事下列何種活動會違反行政中立的要求？ 捐款給特定的政黨  加入政黨成為黨員  兼任地方黨部主委  假日參加政黨遊行', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
