  ('retired-10ced7e2-moex-00209', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-3a7b2121', 'sub-retired-10ced7e2-05', NULL, 'single_choice', '學者摩根（G. Morgen）將組織比喻成八種不同的意象，下列敘述何者錯誤？ 組織作為機器的意象，意味著組織是一個精心設計的有機體 組織作為大腦的意象，意指組織可以扮演整合分析之功能 組織作為流變與轉型的意象，代表著組織不斷進行變遷 組織作為宰制工具的意象，說明了組織對於內部員工的壓迫', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
